import React, { useState } from 'react';
import { Citizen, CrimeSeverity, CrimeRecord } from '../types';
import { analyzeCriminalRecord } from '../services/geminiService';

interface CitizenSearchProps {
  citizens: Citizen[];
  onAddRecord: (citizenId: string, record: Partial<CrimeRecord>) => void;
}

const CitizenSearch: React.FC<CitizenSearchProps> = ({ citizens, onAddRecord }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCitizen, setSelectedCitizen] = useState<Citizen | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);

  const [newRecord, setNewRecord] = useState({
    type: '',
    description: '',
    severity: CrimeSeverity.LOW,
    location: '',
  });

  const handleSearch = () => {
    const found = citizens.find(c => 
      c.id.includes(searchTerm) || 
      `${c.firstName} ${c.lastName}`.toLowerCase().includes(searchTerm.toLowerCase())
    );
    setSelectedCitizen(found || null);
    setAiAnalysis(null);
  };

  const handleAiAnalysis = async () => {
    if (!selectedCitizen) return;
    setLoadingAi(true);
    const analysis = await analyzeCriminalRecord(selectedCitizen);
    setAiAnalysis(analysis);
    setLoadingAi(false);
  };

  const handleSubmitRecord = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedCitizen) {
      onAddRecord(selectedCitizen.id, newRecord);
      setIsAdding(false);
      setNewRecord({ type: '', description: '', severity: CrimeSeverity.LOW, location: '' });
      // Refresh citizen view (in a real app, this would be reactive to the state update)
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
        <h2 className="text-xl font-bold mb-4 somali-blue-text">Search Citizen Database</h2>
        <div className="flex gap-2">
          <input
            type="text"
            placeholder="Enter ID Number or Full Name..."
            className="flex-1 border rounded-lg px-4 py-2 focus:ring-2 focus:ring-blue-400 outline-none"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
          />
          <button 
            onClick={handleSearch}
            className="somali-blue text-white px-6 py-2 rounded-lg font-medium hover:bg-blue-600 transition-colors"
          >
            Search
          </button>
        </div>
      </div>

      {selectedCitizen ? (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 animate-fadeIn">
          {/* Profile Card */}
          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
            <div className="flex flex-col items-center text-center">
              <img 
                src={selectedCitizen.photoUrl} 
                alt="Citizen" 
                className="w-32 h-32 rounded-full object-cover border-4 border-blue-50 mb-4"
              />
              <h3 className="text-xl font-bold">{selectedCitizen.firstName} {selectedCitizen.lastName}</h3>
              <p className="text-blue-600 font-medium">ID: {selectedCitizen.id}</p>
              <div className="mt-4 w-full text-left space-y-2 text-sm">
                <p><span className="font-semibold">DOB:</span> {selectedCitizen.dateOfBirth}</p>
                <p><span className="font-semibold">Gender:</span> {selectedCitizen.gender}</p>
                <p><span className="font-semibold">Address:</span> {selectedCitizen.address}</p>
              </div>
            </div>
          </div>

          {/* Records & Actions */}
          <div className="lg:col-span-2 space-y-6">
            <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-bold">Criminal History</h3>
                <div className="flex gap-2">
                  <button 
                    onClick={handleAiAnalysis}
                    className="text-xs bg-purple-50 text-purple-700 px-3 py-1 rounded-full border border-purple-200 hover:bg-purple-100"
                    disabled={loadingAi}
                  >
                    {loadingAi ? 'Analyzing...' : '✨ AI Analysis'}
                  </button>
                  <button 
                    onClick={() => setIsAdding(true)}
                    className="text-xs bg-blue-50 text-blue-700 px-3 py-1 rounded-full border border-blue-200 hover:bg-blue-100"
                  >
                    + Add Charge
                  </button>
                </div>
              </div>

              {aiAnalysis && (
                <div className="mb-6 p-4 bg-purple-50 rounded-lg border border-purple-100 text-sm text-purple-900 leading-relaxed whitespace-pre-wrap">
                  <h4 className="font-bold mb-1 flex items-center">
                    <span className="mr-1">🤖</span> SPF Intelligence Assessment
                  </h4>
                  {aiAnalysis}
                </div>
              )}

              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead>
                    <tr className="border-b text-sm text-gray-500">
                      <th className="pb-3 font-medium">Date</th>
                      <th className="pb-3 font-medium">Type</th>
                      <th className="pb-3 font-medium">Severity</th>
                      <th className="pb-3 font-medium">Status</th>
                    </tr>
                  </thead>
                  <tbody className="text-sm">
                    {selectedCitizen.records.length > 0 ? (
                      selectedCitizen.records.map(record => (
                        <tr key={record.id} className="border-b hover:bg-gray-50">
                          <td className="py-3">{record.date}</td>
                          <td className="py-3">{record.type}</td>
                          <td className="py-3">
                            <span className={`px-2 py-1 rounded text-xs font-bold ${
                              record.severity === CrimeSeverity.CRITICAL ? 'bg-red-100 text-red-700' :
                              record.severity === CrimeSeverity.HIGH ? 'bg-orange-100 text-orange-700' :
                              record.severity === CrimeSeverity.MEDIUM ? 'bg-yellow-100 text-yellow-700' :
                              'bg-green-100 text-green-700'
                            }`}>
                              {record.severity}
                            </span>
                          </td>
                          <td className="py-3 text-gray-600">{record.status}</td>
                        </tr>
                      ))
                    ) : (
                      <tr>
                        <td colSpan={4} className="py-8 text-center text-gray-400 italic">No criminal history found.</td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        </div>
      ) : searchTerm && (
        <div className="bg-white p-12 text-center rounded-xl shadow-sm border border-gray-100">
          <p className="text-gray-500">No citizen found matching "{searchTerm}"</p>
        </div>
      )}

      {/* Add Record Modal */}
      {isAdding && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden">
            <div className="somali-blue p-4 text-white flex justify-between items-center">
              <h3 className="font-bold">Add New Criminal Record</h3>
              <button onClick={() => setIsAdding(false)} className="hover:text-gray-200">✕</button>
            </div>
            <form onSubmit={handleSubmitRecord} className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-medium mb-1">Crime Type</label>
                <input 
                  type="text" 
                  required
                  className="w-full border rounded p-2 text-sm" 
                  placeholder="e.g. Theft, Public Disturbance"
                  value={newRecord.type}
                  onChange={(e) => setNewRecord({...newRecord, type: e.target.value})}
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium mb-1">Severity</label>
                  <select 
                    className="w-full border rounded p-2 text-sm"
                    value={newRecord.severity}
                    onChange={(e) => setNewRecord({...newRecord, severity: e.target.value as CrimeSeverity})}
                  >
                    <option value={CrimeSeverity.LOW}>Low</option>
                    <option value={CrimeSeverity.MEDIUM}>Medium</option>
                    <option value={CrimeSeverity.HIGH}>High</option>
                    <option value={CrimeSeverity.CRITICAL}>Critical</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium mb-1">Location</label>
                  <input 
                    type="text" 
                    required
                    className="w-full border rounded p-2 text-sm" 
                    placeholder="e.g. Mogadishu - District X"
                    value={newRecord.location}
                    onChange={(e) => setNewRecord({...newRecord, location: e.target.value})}
                  />
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">Detailed Description</label>
                <textarea 
                  required
                  className="w-full border rounded p-2 text-sm h-24" 
                  placeholder="Provide incident details..."
                  value={newRecord.description}
                  onChange={(e) => setNewRecord({...newRecord, description: e.target.value})}
                ></textarea>
              </div>
              <div className="flex gap-2 pt-2">
                <button 
                  type="button" 
                  onClick={() => setIsAdding(false)}
                  className="flex-1 bg-gray-100 text-gray-700 py-2 rounded font-medium hover:bg-gray-200"
                >
                  Cancel
                </button>
                <button 
                  type="submit" 
                  className="flex-1 somali-blue text-white py-2 rounded font-medium hover:bg-blue-600"
                >
                  Register Charge
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default CitizenSearch;

