  const [stats, setStats] = useState<DashboardStats>(INITIAL_STATS);

  const t = translations[lang];

  useEffect(() => {
    document.documentElement.dir = t.dir;
    document.documentElement.lang = lang;
  }, [lang, t.dir]);

  const handleAddRecord = (citizenId: string, recordData: Partial<CrimeRecord>) => {
    const newRecord: CrimeRecord = {
      id: `REC-${Math.floor(1000 + Math.random() * 9000)}`,
      date: new Date().toISOString().split('T')[0],
      type: recordData.type || 'Unknown',
      severity: recordData.severity || CrimeSeverity.LOW,
      description: recordData.description || '',
      officerId: "SPF-9921",
      location: recordData.location || 'Unknown',
      status: 'PENDING',
    };

    setCitizens(prev => prev.map(c => 
      c.id === citizenId ? { ...c, records: [newRecord, ...c.records] } : c
    ));

    // Increment total crimes for visual effect
    setStats(prev => ({ ...prev, totalCrimes: prev.totalCrimes + 1 }));
  };

  return (
    <div className={`flex h-screen bg-[#f8fafc] overflow-hidden ${t.dir === 'rtl' ? 'font-serif' : 'font-sans'}`}>
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} lang={lang} />

      <main className="flex-1 overflow-y-auto relative flex flex-col custom-scrollbar">
        {/* State-Level Top Bar */}
        <header className="bg-white px-10 py-6 flex justify-between items-center border-b-2 border-slate-200 z-20 shadow-xl">
          <div className="flex items-center gap-6">
             <div className="w-2.5 h-12 bg-blue-900 rounded-sm"></div>
             <div>
                <h2 className="text-[11px] font-black text-slate-400 uppercase tracking-[0.3em] mb-1 leading-none">{t.subTitle}</h2>
                <p className="text-2xl font-black text-slate-800 tracking-tight leading-none">{t.title}</p>
             </div>
          </div>

          <div className="flex items-center gap-8">
            {/* Elite Language Switcher */}
            <div className="flex bg-slate-100 p-1.5 rounded-xl border-2 border-slate-200 shadow-inner">
              {(['so', 'ar', 'en'] as Language[]).map(l => (
                <button
                  key={l}
                  onClick={() => setLang(l)}
                  className={`px-5 py-2 text-[11px] font-black uppercase rounded-lg transition-all duration-300 ${
                    lang === l ? 'bg-blue-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-200'
                  }`}
                >
                  {l}
                </button>
              ))}
            </div>

            <div className="h-12 w-px bg-slate-200 mx-2"></div>

            <div className={t.dir === 'rtl' ? 'text-left' : 'text-right'}>
               <p className="text-sm font-black text-blue-900 uppercase">Cmdr. Hassan Adan</p>
               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{t.officer} | SPF-9921</p>
            </div>
            <div className="w-14 h-14 bg-slate-800 border-2 border-[#c5a059] flex items-center justify-center text-white text-[11px] font-black shadow-2xl rounded-sm hover:scale-105 transition-transform cursor-pointer">
               SPF
            </div>
          </div>
        </header>

        {/* Dynamic Content Area */}
        <div className="p-10 flex-1 w-full bg-slate-50/50">
          {activeTab === 'dashboard' && <DashboardOverview stats={stats} lang={lang} />}
          {activeTab === 'search' && (
            <CitizenSearch citizens={citizens} onAddRecord={handleAddRecord} lang={lang} />
          )}
          {!['dashboard', 'search'].includes(activeTab) && (
            <div className="flex flex-col items-center justify-center h-[60vh] text-center opacity-40 grayscale">
              <div className="w-32 h-32 bg-white border-2 border-slate-200 rounded-full flex items-center justify-center text-5xl mb-8 shadow-inner">🛡️</div>
              <h3 className="text-lg font-black text-slate-400 uppercase tracking-[0.4em]">Section Restricted</h3>
              <p className="text-xs text-slate-300 mt-4 font-bold uppercase tracking-widest">Level 5 Clearance Required for Access</p>
            </div>
          )}
        </div>

        {/* Professional Footer */}
        <footer className="px-10 py-5 border-t-2 border-slate-200 flex justify-between items-center bg-white shadow-inner">
           <div className="flex items-center gap-3">
              <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">System Online - Encryption Active (AES-256)</p>
           </div>
           <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest opacity-50 italic">SPF Intelligence Network © 2024</p>
        </footer>
      </main>
    </div>
  );
};

export default App;

