import React, { useState } from 'react';
import { Citizen, CrimeSeverity, CrimeRecord } from '../types';
import { analyzeCriminalRecord, suggestCrimeClassification } from '../services/geminiService';
import { translations, Language } from '../translations';

interface CitizenSearchProps {
  citizens: Citizen[];
  onAddRecord: (citizenId: string, record: Partial<CrimeRecord>) => void;
  lang: Language;
}

const CitizenSearch: React.FC<CitizenSearchProps> = ({ citizens, onAddRecord, lang }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCitizen, setSelectedCitizen] = useState<Citizen | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);
  const [suggesting, setSuggesting] = useState(false);
  const spfLogo = "https://upload.wikimedia.org/wikipedia/commons/1/10/Somali_Police_Force_Seal.png";

  const [formData, setFormData] = useState({
    type: '',
    description: '',
    location: '',
    severity: CrimeSeverity.LOW
  });

  const t = translations[lang];

  const handleSearch = () => {
    const found = citizens.find(c => 
      c.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
      `${c.firstName} ${c.lastName}`.toLowerCase().includes(searchTerm.toLowerCase())
    );
    setSelectedCitizen(found || null);
    setAiAnalysis(null);
  };

  const handleAiAnalysis = async () => {
    if (!selectedCitizen) return;
    setLoadingAi(true);
    const analysis = await analyzeCriminalRecord(selectedCitizen);
    setAiAnalysis(analysis);
    setLoadingAi(false);
  };

  const handleAISuggestion = async () => {
    if (!formData.description) return;
    setSuggesting(true);
    const suggestion = await suggestCrimeClassification(formData.description);
    if (suggestion) {
      setFormData(prev => ({
        ...prev,
        type: suggestion.classification || prev.type,
        severity: (suggestion.severity as CrimeSeverity) || prev.severity
      }));
    }
    setSuggesting(false);
  };

  const handleSubmitCrime = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedCitizen) return;
    onAddRecord(selectedCitizen.id, { ...formData, status: 'PENDING' });
    setFormData({ type: '', description: '', location: '', severity: CrimeSeverity.LOW });
    setIsAdding(false);
  };

  return (
    <div className="space-y-8 animate-fadeIn max-w-7xl mx-auto pb-16">
      {/* Search Module - Elite Style */}
      <div className="bg-white p-8 border-b-4 border-blue-900 shadow-xl relative overflow-hidden group">
        <div className="official-seal-bg absolute inset-0 opacity-[0.05] group-hover:scale-105 transition-transform duration-[2s]"></div>
        <div className="relative z-10">
          <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-4 block">
            {t.subTitle}
          </label>
          <div className="flex flex-col md:flex-row gap-4">
            <div className="flex-1 relative">
              <span className={`absolute ${lang === 'ar' ? 'right-6' : 'left-6'} top-1/2 -translate-y-1/2 text-slate-300`}>🔍</span>
              <input
                type="text"
                placeholder={t.searchPlaceholder}
                className={`w-full border-2 border-slate-100 bg-slate-50 ${lang === 'ar' ? 'pr-14 pl-6' : 'pl-14 pr-6'} py-5 font-bold text-slate-800 focus:border-blue-900 outline-none transition-all shadow-inner text-lg`}
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
              />
            </div>
            <button 
              onClick={handleSearch}
              className="bg-blue-900 text-white px-12 py-5 font-black uppercase tracking-widest hover:bg-black transition-all shadow-xl active:scale-95 flex items-center justify-center gap-2"
            >
              {t.searchBtn}
            </button>
          </div>
        </div>
      </div>

      {selectedCitizen ? (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
          {/* Official Dossier Sidebar */}
          <div className="lg:col-span-4 space-y-6">
            <div className="bg-white border-2 border-slate-100 shadow-2xl dossier-card overflow-hidden">
              <div className="p-10 text-center bg-gradient-to-b from-slate-50 to-white">
                 <div className="w-48 h-48 bg-white border-8 border-slate-100 mx-auto mb-6 p-1 relative shadow-2xl">
                    <img src={selectedCitizen.photoUrl} alt="Subject" className="w-full h-full object-cover grayscale contrast-125" />
                    <div className={`absolute -bottom-4 ${lang === 'ar' ? '-left-4' : '-right-4'} bg-blue-900 text-white px-5 py-2 text-[10px] font-black tracking-widest shadow-xl border-2 border-white`}>
                      {t.verified}
                    </div>
                 </div>
                 <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tight mb-1">
                   {selectedCitizen.firstName} {selectedCitizen.lastName}
                 </h3>
                 <p className="text-blue-800 font-black text-xs uppercase tracking-[0.3em] bg-blue-50 py-1 inline-block px-4 rounded-full">
