                    <p className="text-xs font-bold text-slate-700">{selectedCitizen.gender === 'MALE' ? t.male : t.female}</p>
                  </div>
                  <div className="p-4 bg-slate-50 border border-slate-100">
                    <p className="text-[10px] font-black text-slate-400 uppercase mb-1">{t.dob}</p>
                    <p className="text-xs font-bold text-slate-700">{selectedCitizen.dateOfBirth}</p>
                  </div>
                </div>
                <div className="p-4 bg-slate-50 border border-slate-100">
                  <p className="text-[10px] font-black text-slate-400 uppercase mb-1">{t.address}</p>
                  <p className="text-xs font-bold text-slate-700 leading-relaxed">{selectedCitizen.address}</p>
                </div>
              </div>
            </div>

            <button 
              onClick={() => setIsAdding(true)}
              className="w-full bg-red-900 text-white py-6 font-black uppercase tracking-widest hover:bg-black transition-all shadow-2xl flex items-center justify-center gap-4 group active:scale-95"
            >
              <span className="text-2xl group-hover:rotate-12 transition-transform">⚖️</span>
              {t.addCharge}
            </button>
          </div>

          {/* AI Center & Records */}
          <div className="lg:col-span-8 space-y-8">
            <div className="bg-[#0c1e3d] p-10 text-white border-l-8 border-[#c5a059] shadow-2xl relative overflow-hidden">
