                  <h3 className="text-sm font-black tracking-[0.2em] uppercase text-[#c5a059] flex items-center gap-4">
                    <span className="w-3 h-3 rounded-full bg-[#c5a059] emergency-pulse shadow-[0_0_15px_#c5a059]"></span>
                    {t.aiAnalysis}
                  </h3>
                  {!aiAnalysis && (
                    <button 
                      onClick={handleAiAnalysis}
                      disabled={loadingAi}
                      className="text-[10px] font-black px-8 py-3 bg-[#c5a059] text-slate-900 hover:bg-white transition-all uppercase tracking-[0.2em] shadow-lg disabled:opacity-50"
                    >
                      {loadingAi ? t.scanning : t.runScan}
                    </button>
                  )}
                </div>

                {aiAnalysis ? (
                  <div className="p-8 bg-black/40 border border-white/5 font-mono text-xs leading-relaxed text-slate-300 backdrop-blur-sm rounded">
                    <p className="whitespace-pre-wrap">{aiAnalysis}</p>
                    <button 
                      onClick={() => setAiAnalysis(null)} 
                      className="mt-6 text-[10px] text-slate-500 hover:text-white uppercase font-black tracking-widest transition-colors flex items-center gap-2"
