          <div className="text-8xl mb-8 opacity-10">🛡️</div>
          <p className="text-slate-400 font-black uppercase text-sm tracking-[0.5em] mb-4">{t.noMatches}</p>
          <p className="text-slate-300 text-[10px] font-bold uppercase tracking-widest">{t.verifyFormat}</p>
