                           onChange={e => setFormData({...formData, location: e.target.value})}
                         />
                      </div>
                   </div>

                   <div className="space-y-4">
                      <label className="text-[11px] font-black text-slate-500 uppercase tracking-widest block">{t.severity}</label>
                      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                         {[CrimeSeverity.LOW, CrimeSeverity.MEDIUM, CrimeSeverity.HIGH, CrimeSeverity.CRITICAL].map(lvl => (
                           <button
                             type="button"
                             key={lvl}
                             onClick={() => setFormData({...formData, severity: lvl})}
                             className={`py-4 px-2 text-[10px] font-black uppercase border-2 transition-all ${
                               formData.severity === lvl 
                               ? 'bg-red-900 border-red-900 text-white shadow-xl scale-105 z-10' 
                               : 'bg-white border-slate-100 text-slate-400 hover:border-slate-200'
                             }`}
                           >
                             {lang === 'ar' ? t[lvl.toLowerCase() as keyof typeof t] : lvl}
                           </button>
                         ))}
                      </div>
                   </div>

                   <div className="flex flex-col md:flex-row gap-4 pt-10 border-t-2 border-slate-100">
                      <button 
                        type="button" 
                        onClick={() => setIsAdding(false)}
                        className="flex-1 py-6 border-2 border-slate-100 text-[11px] font-black uppercase tracking-widest text-slate-400 hover:bg-slate-50 transition-all"
                      >
                         {t.cancel}
                      </button>
                      <button 
                        type="submit"
                        className="flex-[2] py-6 bg-red-900 text-white text-[11px] font-black uppercase tracking-[0.3em] shadow-2xl hover:bg-black transition-all active:scale-95 flex items-center justify-center gap-3"
                      >
                         <span>📜</span> {t.submit}
                      </button>
                   </div>
                </form>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CitizenSearch;

