import React, { useState } from 'react';
import { Citizen, CrimeSeverity, CrimeRecord } from '../types';
import { analyzeCriminalRecord, suggestCrimeClassification } from '../services/geminiService';
import { translations, Language } from '../translations';

interface CitizenSearchProps {
  citizens: Citizen[];
  onAddRecord: (citizenId: string, record: Partial<CrimeRecord>) => void;
  lang: Language;
}

const CitizenSearch: React.FC<CitizenSearchProps> = ({ citizens, onAddRecord, lang }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCitizen, setSelectedCitizen] = useState<Citizen | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);
  const [suggesting, setSuggesting] = useState(false);

  // الشعار الرسمي الصومالي
  const spfLogo = "https://upload.wikimedia.org/wikipedia/commons/thumb/1/10/Somali_Police_Force_Seal.png/800px-Somali_Police_Force_Seal.png";

  const [formData, setFormData] = useState({
    type: '',
    description: '',
    location: '',
    severity: CrimeSeverity.LOW
  });

  const t = translations[lang];

  const handleSearch = () => {
    const found = citizens.find(c => 
      c.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
      `${c.firstName} ${c.lastName}`.toLowerCase().includes(searchTerm.toLowerCase())
    );
    setSelectedCitizen(found || null);
    setAiAnalysis(null);
  };

  const handleAiAnalysis = async () => {
    if (!selectedCitizen) return;
    setLoadingAi(true);
    const analysis = await analyzeCriminalRecord(selectedCitizen);
    setAiAnalysis(analysis);
    setLoadingAi(false);
  };

  const handleAISuggestion = async () => {
    if (!formData.description) return;
    setSuggesting(true);
    const suggestion = await suggestCrimeClassification(formData.description);
    if (suggestion) {
      setFormData(prev => ({
        ...prev,
        type: suggestion.classification || prev.type,
        severity: (suggestion.severity as CrimeSeverity) || prev.severity
      }));
    }
    setSuggesting(false);
  };

  const handleSubmitCrime = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedCitizen) return;
    onAddRecord(selectedCitizen.id, { ...formData, status: 'PENDING' });
    setFormData({ type: '', description: '', location: '', severity: CrimeSeverity.LOW });
    setIsAdding(false);
  };

  return (
    <div className="space-y-8 animate-fadeIn max-w-7xl mx-auto pb-16">
      {/* وحدة البحث الفيدرالي */}
      <div className="bg-white p-10 border-b-8 border-blue-900 shadow-2xl relative overflow-hidden group rounded-xl">
        <div className="official-seal-bg absolute inset-0 opacity-[0.04] group-hover:scale-105 transition-transform duration-[3s]"></div>
        <div className="relative z-10">
          <label className="text-[11px] font-black text-slate-400 uppercase tracking-[0.4em] mb-5 block">
            {t.subTitle}
          </label>
          <div className="flex flex-col md:flex-row gap-5">
            <div className="flex-1 relative">
              <span className={`absolute ${lang === 'ar' ? 'right-7' : 'left-7'} top-1/2 -translate-y-1/2 text-slate-300 text-xl`}>🔍</span>
              <input
                type="text"
                placeholder={t.searchPlaceholder}
                className={`w-full border-2 border-slate-100 bg-slate-50 ${lang === 'ar' ? 'pr-16 pl-8' : 'pl-16 pr-8'} py-6 font-black text-slate-800 focus:border-blue-900 outline-none transition-all shadow-inner text-xl placeholder:text-slate-300`}
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
              />
            </div>
            <button 
              onClick={handleSearch}
              className="bg-blue-900 text-white px-16 py-6 font-black uppercase tracking-[0.2em] hover:bg-black transition-all shadow-2xl active:scale-95 flex items-center justify-center gap-3 text-lg"
            >
              {t.searchBtn}
            </button>
          </div>
        </div>
      </div>

      {selectedCitizen ? (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 items-start">
          {/* ملف المواطن - Dossier */}
          <div className="lg:col-span-4 space-y-8">
            <div className="bg-white border-2 border-slate-100 shadow-2xl dossier-card overflow-hidden rounded-xl">
              <div className="p-12 text-center bg-gradient-to-b from-slate-50 to-white relative">
                 <div className="w-56 h-56 bg-white border-[12px] border-slate-100 mx-auto mb-8 p-1 relative shadow-2xl ring-1 ring-slate-200">
                    <img src={selectedCitizen.photoUrl} alt="Subject" className="w-full h-full object-cover grayscale contrast-[1.1] brightness-[1.05]" />
                    <div className={`absolute -bottom-5 ${lang === 'ar' ? '-left-5' : '-right-5'} bg-blue-900 text-white px-6 py-2.5 text-[11px] font-black tracking-widest shadow-2xl border-2 border-white uppercase`}>
