                              record.severity === CrimeSeverity.MEDIUM ? 'bg-blue-50 text-blue-900 border-blue-200' :
                              'bg-slate-50 text-slate-600 border-slate-200'
                            }`}>
                              {lang === 'ar' ? t[record.severity.toLowerCase() as keyof typeof t] : record.severity}
                            </span>
                          </td>
                          <td className={`px-10 py-8 text-[11px] font-mono font-black text-slate-300 group-hover:text-slate-800 transition-colors ${lang === 'ar' ? 'text-left' : 'text-right'}`}>
                            #{record.id}
                          </td>
                        </tr>
                      ))
                    ) : (
                      <tr>
                        <td colSpan={4} className="px-10 py-32 text-center">
                          <div className="w-20 h-20 mx-auto mb-6 opacity-10">
                            <img src={spfLogo} alt="Seal" className="grayscale" />
                          </div>
                          <p className="text-[12px] font-black text-slate-300 uppercase tracking-[0.5em]">
                            {t.noRecords}
                          </p>
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        </div>
      ) : searchTerm && (
        <div className="bg-white p-40 text-center border-4 border-dashed border-slate-100 flex flex-col items-center rounded-2xl">
          <div className="w-32 h-32 mb-10 opacity-10 grayscale">
