          <p className="text-slate-400 font-black uppercase text-lg tracking-[0.5em] mb-6">{t.noMatches}</p>
          <p className="text-slate-300 text-xs font-black uppercase tracking-[0.25em]">{t.verifyFormat}</p>
        </div>
      )}

      {/* نموذج إضافة الجريمة - الوثيقة الرسمية */}
