        <div className="fixed inset-0 z-50 flex items-center justify-center p-8 backdrop-blur-2xl bg-slate-950/80 animate-fadeIn overflow-y-auto">
          <div className="bg-white w-full max-w-4xl shadow-[0_0_100px_rgba(0,0,0,0.5)] border-t-[20px] border-red-900 relative my-10 rounded-xl">
