                        <label className="text-[12px] font-black text-slate-500 uppercase tracking-[0.2em]">
                          {t.description}
                        </label>
                        <button 
                          type="button"
                          disabled={!formData.description || suggesting}
                          onClick={handleAISuggestion}
                          className="text-[10px] font-black text-blue-900 hover:text-white hover:bg-blue-900 uppercase tracking-[0.15em] flex items-center gap-3 px-5 py-2.5 bg-blue-50 border-2 border-blue-100 disabled:opacity-30 transition-all shadow-md rounded-lg active:scale-95"
