                          {suggesting ? t.analyzing : `💡 ${t.aiAssist}`}
                        </button>
                      </div>
                      <textarea 
                        required
                        className="w-full bg-slate-50 border-2 border-slate-100 p-8 text-base font-semibold h-48 focus:border-red-900 outline-none transition-all resize-none shadow-inner rounded-xl"
                        placeholder="Detail the circumstances, weapon usage, and arrest summary..."
                        value={formData.description}
                        onChange={e => setFormData({...formData, description: e.target.value})}
                      ></textarea>
                   </div>

                   <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
                      <div className="space-y-4">
                         <label className="text-[12px] font-black text-slate-500 uppercase tracking-[0.2em] px-2">{t.type}</label>
