                           required
                           type="text" 
                           className="w-full bg-slate-50 border-2 border-slate-100 p-6 text-base font-black focus:border-red-900 outline-none transition-all rounded-xl shadow-sm"
                           value={formData.type}
                           onChange={e => setFormData({...formData, type: e.target.value})}
                         />
                      </div>
                      <div className="space-y-4">
                         <label className="text-[12px] font-black text-slate-500 uppercase tracking-[0.2em] px-2">{t.location}</label>
                         <input 
                           required
                           type="text" 
                           className="w-full bg-slate-50 border-2 border-slate-100 p-6 text-base font-black focus:border-red-900 outline-none transition-all rounded-xl shadow-sm"
                           value={formData.location}
                           onChange={e => setFormData({...formData, location: e.target.value})}
                         />
                      </div>
                   </div>

                   <div className="space-y-5">
                      <label className="text-[12px] font-black text-slate-500 uppercase tracking-[0.2em] block px-2">{t.severity}</label>
                      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                         {[CrimeSeverity.LOW, CrimeSeverity.MEDIUM, CrimeSeverity.HIGH, CrimeSeverity.CRITICAL].map(lvl => (
                           <button
                             type="button"
                             key={lvl}
                             onClick={() => setFormData({...formData, severity: lvl})}
                             className={`py-5 px-3 text-[11px] font-black uppercase border-4 transition-all rounded-xl shadow-lg ${
                               formData.severity === lvl 
                               ? 'bg-red-900 border-red-900 text-white scale-105 z-10 ring-4 ring-red-900/20' 
                               : 'bg-white border-slate-100 text-slate-400 hover:border-slate-300'
                             }`}
                           >
                             {lang === 'ar' ? t[lvl.toLowerCase() as keyof typeof t] : lvl}
                           </button>
                         ))}
                      </div>
                   </div>

                   <div className="flex flex-col md:flex-row gap-6 pt-12 border-t-2 border-slate-100">
                      <button 
                        type="button" 
                        onClick={() => setIsAdding(false)}
                        className="flex-1 py-7 border-2 border-slate-100 text-[12px] font-black uppercase tracking-[0.25em] text-slate-400 hover:bg-slate-50 transition-all rounded-xl"
                      >
                         {t.cancel}
                      </button>
                      <button 
                        type="submit"
                        className="flex-[2] py-7 bg-red-900 text-white text-[12px] font-black uppercase tracking-[0.4em] shadow-2xl hover:bg-black transition-all active:scale-95 flex items-center justify-center gap-4 rounded-xl border-b-8 border-red-950"
                      >
                         <span className="text-2xl">📜</span> {t.submit}
                      </button>
                   </div>
                </form>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

