import React, { useState } from 'react';
import { Citizen, CrimeSeverity, CrimeRecord } from '../types';
import { analyzeCriminalRecord, suggestCrimeClassification } from '../services/geminiService';
import { translations, Language } from '../translations';

interface CitizenSearchProps {
  citizens: Citizen[];
  onAddRecord: (citizenId: string, record: Partial<CrimeRecord>) => void;
  lang: Language;
}

const CitizenSearch: React.FC<CitizenSearchProps> = ({ citizens, onAddRecord, lang }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCitizen, setSelectedCitizen] = useState<Citizen | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);
  const [suggesting, setSuggesting] = useState(false);
  const spfLogo = "https://upload.wikimedia.org/wikipedia/commons/thumb/1/10/Somali_Police_Force_Seal.png/800px-Somali_Police_Force_Seal.png";

  const [formData, setFormData] = useState({
    type: '',
    description: '',
    location: '',
    severity: CrimeSeverity.LOW
  });

  const t = translations[lang];

  const handleSearch = () => {
    const found = citizens.find(c => 
      c.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
      `${c.firstName} ${c.lastName}`.toLowerCase().includes(searchTerm.toLowerCase())
    );
    setSelectedCitizen(found || null);
    setAiAnalysis(null);
  };

  const handleAiAnalysis = async () => {
    if (!selectedCitizen) return;
    setLoadingAi(true);
    const analysis = await analyzeCriminalRecord(selectedCitizen);
    setAiAnalysis(analysis);
    setLoadingAi(false);
  };

  const handleAISuggestion = async () => {
    if (!formData.description) return;
    setSuggesting(true);
    const suggestion = await suggestCrimeClassification(formData.description);
    if (suggestion) {
      setFormData(prev => ({
        ...prev,
        type: suggestion.classification || prev.type,
        severity: (suggestion.severity as CrimeSeverity) || prev.severity
      }));
    }
    setSuggesting(false);
  };

  const handleSubmitCrime = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedCitizen) return;
    onAddRecord(selectedCitizen.id, { ...formData, status: 'PENDING' });
    setFormData({ type: '', description: '', location: '', severity: CrimeSeverity.LOW });
    setIsAdding(false);
  };

  return (
    <div className="space-y-12 animate-in max-w-7xl mx-auto pb-20">
      {/* Dynamic Search Unit */}
      <div className="glass-card p-12 rounded-[3rem] shadow-2xl relative overflow-hidden group">
        <div className="official-seal-bg absolute inset-0 opacity-[0.03] group-hover:scale-110 transition-transform duration-[5s]"></div>
        <div className="relative z-10">
          <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.5em] mb-6 block text-center md:text-left">
            {t.subTitle}
          </label>
          <div className="flex flex-col md:flex-row gap-6">
            <div className="flex-1 relative group/input">
              <span className={`absolute ${t.dir === 'rtl' ? 'right-8' : 'left-8'} top-1/2 -translate-y-1/2 text-2xl transition-colors ${searchTerm ? 'text-[#c5a059]' : 'text-slate-300'}`}>🔍</span>
              <input
                type="text"
                placeholder={t.searchPlaceholder}
                className={`w-full bg-slate-50/50 border-2 border-slate-100 rounded-[2rem] ${t.dir === 'rtl' ? 'pr-20 pl-10' : 'pl-20 pr-10'} py-8 font-black text-slate-800 focus:border-[#0c1e3d] focus:bg-white outline-none transition-all shadow-inner text-2xl placeholder:text-slate-200`}
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
              />
            </div>
            <button 
              onClick={handleSearch}
              className="btn-premium text-white px-16 py-8 font-black uppercase tracking-[0.25em] rounded-[2rem] active:scale-95 text-lg shadow-xl"
            >
              {t.searchBtn}
            </button>
          </div>
        </div>
      </div>

      {selectedCitizen ? (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 items-start">
          {/* Detailed Citizen Dossier */}
          <div className="lg:col-span-4 space-y-10">
            <div className="glass-card rounded-[3rem] overflow-hidden group hover:shadow-2xl transition-all duration-500">
              <div className="p-16 text-center bg-gradient-to-b from-slate-50/50 to-transparent relative">
