  const spfLogo = "https://upload.wikimedia.org/wikipedia/commons/thumb/1/10/Somali_Police_Force_Seal.png/800px-Somali_Police_Force_Seal.png";

  const t = translations[lang];

  useEffect(() => {
    document.documentElement.dir = t.dir;
    document.documentElement.lang = lang;
  }, [lang, t.dir]);

  const handleAddRecord = (citizenId: string, recordData: Partial<CrimeRecord>) => {
    const newRecord: CrimeRecord = {
      id: `REC-${Math.floor(1000 + Math.random() * 9000)}`,
      date: new Date().toISOString().split('T')[0],
      type: recordData.type || 'Unknown',
      severity: recordData.severity || CrimeSeverity.LOW,
      description: recordData.description || '',
      officerId: "SPF-9921",
      location: recordData.location || 'Unknown',
      status: 'PENDING',
    };

    setCitizens(prev => prev.map(c => 
      c.id === citizenId ? { ...c, records: [newRecord, ...c.records] } : c
    ));

    setStats(prev => ({ ...prev, totalCrimes: prev.totalCrimes + 1 }));
  };

  if (!isLoggedIn) {
    return <Login onLogin={() => setIsLoggedIn(true)} lang={lang} onLangChange={setLang} />;
  }

  return (
    <div className={`flex h-screen bg-slate-50 overflow-hidden font-medium`}>
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} lang={lang} />

      <main className="flex-1 overflow-y-auto relative flex flex-col custom-scrollbar">
        {/* Modern Header */}
        <header className="sticky top-0 z-40 px-10 py-5 bg-white/70 backdrop-blur-xl flex justify-between items-center border-b border-slate-200/60 shadow-sm">
          <div className="flex items-center gap-6">
             <div className="w-1.5 h-10 bg-[#c5a059] rounded-full"></div>
             <div>
                <h2 className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.4em] mb-0.5">{t.subTitle}</h2>
                <p className="text-xl font-black text-slate-900 tracking-tight">{t.title}</p>
             </div>
          </div>

          <div className="flex items-center gap-6">
            {/* Globe Language Switcher */}
            <div className="relative">
              <button 
                onClick={() => setShowLangMenu(!showLangMenu)}
                className="w-12 h-12 rounded-full glass-card border-slate-200 flex items-center justify-center text-2xl hover:bg-slate-50 transition-all active:scale-90 group relative overflow-hidden"
                title="Change Language"
              >
                <span className="globe-rotate">🌍</span>
                <div className="absolute inset-0 bg-blue-500/5 group-hover:bg-blue-500/10 transition-colors"></div>
              </button>

              {showLangMenu && (
                <div className={`absolute top-14 ${t.dir === 'rtl' ? 'left-0' : 'right-0'} w-48 glass-card border-slate-200 rounded-2xl overflow-hidden shadow-2xl p-2 z-50 animate-in`}>
                  {(['so', 'ar', 'en'] as Language[]).map(l => (
                    <button
                      key={l}
                      onClick={() => { setLang(l); setShowLangMenu(false); }}
                      className={`w-full text-left px-5 py-3 rounded-xl text-xs font-bold uppercase tracking-wider transition-all flex items-center justify-between ${
                        lang === l ? 'bg-[#0c1e3d] text-white' : 'text-slate-600 hover:bg-slate-100'
                      }`}
                    >
                      <span>{l === 'so' ? 'Af-Soomaali' : l === 'ar' ? 'العربية' : 'English'}</span>
                      {lang === l && <span className="text-emerald-400">●</span>}
                    </button>
                  ))}
                </div>
              )}
            </div>

            <div className="h-10 w-px bg-slate-200 mx-1"></div>

            <div className={`flex items-center gap-4 ${t.dir === 'rtl' ? 'flex-row-reverse' : 'flex-row'}`}>
               <div className={t.dir === 'rtl' ? 'text-left' : 'text-right'}>
                  <p className="text-sm font-black text-slate-900 leading-tight">Cmdr. Hassan Adan</p>
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{t.officer}</p>
               </div>
               <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-[#0c1e3d] to-[#162a4d] p-1.5 shadow-lg shadow-blue-900/10 group hover:rotate-6 transition-transform cursor-pointer">
                  <img src={spfLogo} alt="Officer Avatar" className="w-full h-full object-contain brightness-110" />
               </div>
               <button 
                onClick={() => setIsLoggedIn(false)}
                className="w-10 h-10 flex items-center justify-center text-slate-400 hover:text-red-500 transition-colors"
                title="Logout"
               >
                 🚪
               </button>
            </div>
          </div>
        </header>

        {/* Workspace */}
        <div className="p-10 flex-1 relative">
          <div className="absolute top-0 left-0 w-full h-full official-seal-bg pointer-events-none opacity-[0.02]"></div>

          <div className="relative z-10">
            {activeTab === 'dashboard' && <DashboardOverview stats={stats} lang={lang} />}
            {activeTab === 'search' && (
              <CitizenSearch citizens={citizens} onAddRecord={handleAddRecord} lang={lang} />
            )}
            {!['dashboard', 'search'].includes(activeTab) && (
              <div className="flex flex-col items-center justify-center h-[50vh] text-center opacity-40">
                <div className="w-40 h-40 bg-white border border-slate-200 rounded-3xl flex items-center justify-center text-6xl mb-10 shadow-inner p-8">
                  <img src={spfLogo} alt="Restricted" className="w-full h-full object-contain grayscale" />
                </div>
                <h3 className="text-xl font-black text-slate-400 uppercase tracking-[0.5em]">Classified Access</h3>
                <p className="text-xs text-slate-400 mt-4 font-bold uppercase tracking-widest">Biometric Authorization Required</p>
              </div>
            )}
          </div>
        </div>

        {/* Sophisticated Footer */}
        <footer className="px-10 py-4 border-t border-slate-200 bg-white/50 backdrop-blur-md flex justify-between items-center">
           <div className="flex items-center gap-3">
              <span className="relative flex h-2.5 w-2.5">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-2.5 w-2.5 bg-emerald-500"></span>
              </span>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em]">Quantum Security Protocol Active</p>
           </div>
           <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest italic opacity-40">Ciidanka Booliska Soomaaliyeed © 2024</p>
        </footer>
      </main>
    </div>
  );
};

export default App;

